(function(){
'use strict';
const $=(s,r=document)=>r.querySelector(s);
const $$=(s,r=document)=>Array.from(r.querySelectorAll(s));
const API='/api/contributions';
const state={ready:false,page:1,pageSize:20,search:'',year:'',campaign:null,catalogs:null};
const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[c]));
const num=v=>new Intl.NumberFormat('vi-VN').format(Number(v||0));
const money=v=>new Intl.NumberFormat('vi-VN').format(Number(v||0));
const toast=(m,t='success')=>typeof showToast==='function'?showToast(m,t):console[t==='danger'?'error':'log'](m);
async function req(url,opt={}){ if(typeof api==='function')return api(url,opt); const token=window.App?.token||localStorage.getItem('thon09_token')||''; const init={method:opt.method||'GET',headers:{Accept:'application/json',Authorization:token?'Bearer '+token:''}}; if(opt.body){init.headers['Content-Type']='application/json';init.body=JSON.stringify(opt.body);} const r=await fetch(url,init); const j=await r.json().catch(()=>null); if(!r.ok||j?.ok===false)throw new Error(j?.error?.message||'Không tải được dữ liệu'); return j?.data??j;}
function can(action){const role=(window.App?.user?.role||'').toUpperCase(); if(['SUPER_ADMIN','ADMIN'].includes(role))return true; if(role==='OFFICER')return ['read','create','update'].includes(action); if(role==='VIEWER')return action==='read'; return true;}
document.addEventListener('DOMContentLoaded',init);
document.addEventListener('thon09:screen-change',e=>{if(e.detail?.screen==='contributions')load();});
function init(){ if($('#contributionsScreen')?.classList.contains('active'))load(); }
function shell(){
const host=$('#contributionsScreen'); if(!host||state.ready)return;
host.classList.remove('module-placeholder-screen');
host.innerHTML=[
'<section id="contributionStats" class="dashboard-kpi-grid mb-3"></section>',
'<section id="contributionCharts" class="row g-3 mb-3"></section>',
'<section class="content-card module-filter-card"><div class="module-page-head"><div><h2>Đóng góp hộ</h2><p class="text-muted mb-0">Quản lý khoản thu, miễn giảm, công nợ và lịch sử thu theo hộ/khẩu.</p></div><div class="d-flex gap-2 flex-wrap"><button id="contributionReportBtn" class="btn btn-outline-primary" type="button"><i class="fa-solid fa-chart-pie"></i> Báo cáo</button><button id="contributionExportExcel" class="btn btn-outline-success" type="button"><i class="fa-solid fa-file-excel"></i> Excel</button><button id="contributionExportPdf" class="btn btn-outline-danger" type="button"><i class="fa-solid fa-file-pdf"></i> PDF</button><button id="contributionAddBtn" class="btn btn-success" type="button"><i class="fa-solid fa-plus"></i> Thêm đợt thu</button></div></div><div class="row g-2"><div class="col-md-6"><label class="form-label">Tìm kiếm</label><input id="contributionSearch" class="form-control" placeholder="Tên khoản thu, đợt thu, ghi chú..."></div><div class="col-md-3"><label class="form-label">Năm</label><input id="contributionYearFilter" type="number" class="form-control" placeholder="2026"></div><div class="col-md-3 d-flex align-items-end"><button id="contributionResetBtn" class="btn btn-outline-secondary w-100" type="button"><i class="fa-solid fa-rotate-left"></i> Làm mới</button></div></div></section>',
'<section class="module-list-card household-list-card mt-3"><div class="module-list-head"><div><h3>Danh sách đợt thu</h3><span id="contributionsTotal">Tổng số: 0 đợt thu</span></div><select id="contributionsPageSize" class="form-select w-auto"><option>20</option><option>50</option><option>100</option></select></div><div class="table-responsive"><table class="table module-table align-middle mb-0"><thead><tr><th>STT</th><th>Khoản thu</th><th>Năm</th><th>Đơn vị</th><th>Hộ đã nộp</th><th>Nộp một phần</th><th>Chưa nộp</th><th>Được miễn</th><th>Phải thu</th><th>Đã thu</th><th class="text-end">Thao tác</th></tr></thead><tbody id="contributionsRows"></tbody></table></div><div id="contributionsPager" class="pager module-pager"></div></section>',
'<section id="contributionTrackingCard" class="module-list-card household-list-card mt-3 d-none"><div class="module-list-head"><div><h3 id="contributionTrackingTitle">Theo dõi hộ</h3><span id="contributionTrackingTotal">Tổng số: 0 hộ</span></div><select id="contributionPaymentFilter" class="form-select w-auto"><option value="">Tất cả</option><option value="PAID">Đã nộp</option><option value="PARTIAL">Nộp một phần</option><option value="UNPAID">Chưa nộp</option><option value="EXEMPT">Được miễn</option><option value="REDUCED">Miễn một phần</option></select></div><div class="table-responsive"><table class="table module-table align-middle mb-0"><thead><tr><th>Mã hộ</th><th>Chủ hộ</th><th>Trạng thái</th><th>Khẩu thu</th><th>Khẩu miễn</th><th>Phải thu</th><th>Đã thu</th><th>Còn nợ</th><th>Biên lai</th><th class="text-end">Thao tác</th></tr></thead><tbody id="contributionTrackingRows"></tbody></table></div></section>',
campaignModal(),paymentModal()
].join('');
bind(); state.ready=true;
}
function campaignModal(){return '<div class="modal fade" id="contributionModal" tabindex="-1"><div class="modal-dialog modal-xl"><form id="contributionForm" class="modal-content"><div class="modal-header"><h5 class="modal-title">Thông tin khoản thu</h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><input type="hidden" name="id"><div class="row g-3"><div class="col-md-4"><label class="form-label">Tên khoản thu</label><input name="contribution_name" class="form-control" required></div><div class="col-md-2"><label class="form-label">Loại khoản thu</label><input name="contribution_type" class="form-control"></div><div class="col-md-2"><label class="form-label">Năm</label><input name="year" type="number" class="form-control" required></div><div class="col-md-2"><label class="form-label">Đợt thu</label><input name="period_name" class="form-control"></div><div class="col-md-2"><label class="form-label">Trạng thái</label><select name="status" id="contributionStatusInput" class="form-select"></select></div><div class="col-md-3"><label class="form-label">Mức thu chuẩn</label><input name="amount" type="number" class="form-control"></div><div class="col-md-3"><label class="form-label">Đơn vị tính</label><select name="unit_type" id="contributionUnitTypeInput" class="form-select"></select></div><div class="col-md-2"><label class="form-label">Ngày bắt đầu</label><input name="start_date" type="date" class="form-control"></div><div class="col-md-2"><label class="form-label">Hạn thu</label><input name="due_date" type="date" class="form-control"></div><div class="col-md-2"><label class="form-label">Đơn vị hiển thị</label><input name="unit" class="form-control" value="VNĐ/hộ"></div><div class="col-md-6"><label class="form-label">Đối tượng phải thu</label><div id="targetConditions" class="module-check-grid"></div></div><div class="col-md-6"><label class="form-label">Đối tượng được miễn</label><div id="exemptionConditions" class="module-check-grid"></div></div><div class="col-md-2"><label class="form-label">Từ tuổi</label><input name="age_from" type="number" class="form-control"></div><div class="col-md-2"><label class="form-label">Đến tuổi</label><input name="age_to" type="number" class="form-control"></div><div class="col-12"><label class="form-label">Ghi chú</label><textarea name="note" class="form-control" rows="2"></textarea></div></div></div><div class="modal-footer"><button type="button" class="btn btn-outline-secondary" data-bs-dismiss="modal">Đóng</button><button class="btn btn-success" type="submit">Lưu</button></div></form></div></div>';}
function paymentModal(){return '<div class="modal fade" id="contributionPaymentModal" tabindex="-1"><div class="modal-dialog"><form id="contributionPaymentForm" class="modal-content"><div class="modal-header"><h5 class="modal-title">Cập nhật thu tiền</h5><button type="button" class="btn-close" data-bs-dismiss="modal"></button></div><div class="modal-body"><input type="hidden" name="campaign_id"><input type="hidden" name="household_id"><p id="contributionPaymentHousehold" class="fw-semibold"></p><div class="row g-3"><div class="col-md-6"><label class="form-label">Trạng thái</label><select name="payment_status" id="paymentStatusInput" class="form-select"></select></div><div class="col-md-6"><label class="form-label">Số tiền đã thu</label><input name="paid_amount" type="number" class="form-control"></div><div class="col-md-6"><label class="form-label">Miễn/giảm thêm</label><input name="discount_amount" type="number" class="form-control"></div><div class="col-md-6"><label class="form-label">Ngày thu</label><input name="paid_at" type="date" class="form-control"></div><div class="col-md-6"><label class="form-label">Người thu</label><input name="collector_name" class="form-control"></div><div class="col-md-6"><label class="form-label">Biên lai</label><input name="receipt_number" class="form-control"></div><div class="col-12"><label class="form-label">Ghi chú</label><textarea name="note" class="form-control" rows="2"></textarea></div></div></div><div class="modal-footer"><button type="button" class="btn btn-outline-secondary" data-bs-dismiss="modal">Đóng</button><button class="btn btn-success" type="submit">Lưu</button></div></form></div></div>';}
function bind(){ $('#contributionSearch').addEventListener('input',debounce(e=>{state.search=e.target.value.trim();state.page=1;load();},300)); $('#contributionYearFilter').addEventListener('input',debounce(e=>{state.year=e.target.value.trim();state.page=1;load();},300)); $('#contributionsPageSize').addEventListener('change',e=>{state.pageSize=Number(e.target.value||20);state.page=1;load();}); $('#contributionResetBtn').onclick=()=>{Object.assign(state,{page:1,search:'',year:''});$('#contributionSearch').value='';$('#contributionYearFilter').value='';load();}; $('#contributionAddBtn').onclick=()=>openCampaign(); $('#contributionForm').addEventListener('submit',saveCampaign); $('#contributionPaymentForm').addEventListener('submit',savePayment); $('#contributionPaymentFilter').onchange=()=>loadTracking(); $('#contributionExportExcel').onclick=()=>exportReport('excel'); $('#contributionExportPdf').onclick=()=>exportReport('pdf'); $('#contributionReportBtn').onclick=()=>exportReport('preview');}
async function catalogs(){ if(state.catalogs)return state.catalogs; state.catalogs=await req(API+'/catalogs',{cacheTtl:60000}); fill('#contributionStatusInput',state.catalogs.campaign_statuses,'Chọn trạng thái'); fill('#paymentStatusInput',state.catalogs.payment_statuses,'Chọn trạng thái'); fill('#contributionUnitTypeInput',state.catalogs.unit_types,'Chọn đơn vị tính'); checks('#targetConditions',state.catalogs.target_options,'target_conditions'); checks('#exemptionConditions',state.catalogs.exemption_options,'exemption_conditions'); return state.catalogs; }
function fill(sel,items,first){const el=$(sel); if(!el)return; el.innerHTML='<option value="">'+esc(first)+'</option>'+(items||[]).map(i=>'<option value="'+esc(i.value)+'">'+esc(i.label||i.value)+'</option>').join('');}
function checks(sel,items,name){const el=$(sel); if(!el)return; el.innerHTML=(items||[]).map(i=>'<label class="form-check"><input class="form-check-input" type="checkbox" name="'+name+'" value="'+esc(i.value)+'"><span class="form-check-label">'+esc(i.label)+'</span></label>').join('');}
function params(){const p=new URLSearchParams({page:state.page,pageSize:state.pageSize}); if(state.search)p.set('search',state.search); if(state.year)p.set('year',state.year); return p;}
async function load(){ if(!can('read'))return; shell(); await catalogs(); try{const data=await req(API+'?'+params().toString(),{cacheTtl:1000}); render(data); dashboard();}catch(e){toast(e.message,'danger');} }
function render(data){const rows=data.items||[]; $('#contributionsTotal').textContent='Tổng số: '+num(data.total)+' đợt thu'; $('#contributionsRows').innerHTML=rows.length?rows.map((r,i)=>row(r,(data.page-1)*data.pageSize+i+1)).join(''):'<tr><td colspan="11" class="text-center text-muted py-4">Chưa có dữ liệu đợt thu</td></tr>'; pager(data); syncLabels($('#contributionsScreen'));}
function row(r,i){const actions='<button class="btn btn-sm btn-outline-secondary me-1" data-track="'+r.id+'" data-name="'+esc(r.contribution_name)+'"><i class="fa-solid fa-list-check"></i></button>'+(can('update')?'<button class="btn btn-sm btn-outline-primary me-1" data-edit="'+r.id+'"><i class="fa-solid fa-pen"></i></button>':'')+(can('delete')?'<button class="btn btn-sm btn-outline-danger" data-del="'+r.id+'"><i class="fa-solid fa-trash"></i></button>':''); return '<tr><td>'+i+'</td><td><strong>'+esc(r.contribution_name)+'</strong><div class="text-muted small">'+esc(r.period_name||'')+'</div></td><td>'+r.year+'</td><td>'+esc(r.unit_type_label||r.unit)+'</td><td>'+num(r.paid_households)+'</td><td>'+num(r.partial_households)+'</td><td>'+num(r.unpaid_households)+'</td><td>'+num(r.exempt_households)+'</td><td>'+money(r.expected_total)+'</td><td>'+money(r.collected_amount)+'</td><td class="text-end">'+actions+'</td></tr>';}
function pager(data){const h=$('#contributionsPager'),page=Number(data.page||1),total=Number(data.totalPages||1); h.innerHTML='<button class="btn btn-sm btn-outline-secondary" '+(page<=1?'disabled':'')+'>Trước</button><span class="px-2">'+page+' / '+total+'</span><button class="btn btn-sm btn-outline-secondary" '+(page>=total?'disabled':'')+'>Sau</button>'; const b=h.querySelectorAll('button'); b[0].onclick=()=>{state.page--;load();}; b[1].onclick=()=>{state.page++;load();}; $$('[data-track]',$('#contributionsRows')).forEach(b=>b.onclick=()=>{state.campaign={id:Number(b.dataset.track),name:b.dataset.name};loadTracking();}); $$('[data-edit]',$('#contributionsRows')).forEach(b=>b.onclick=()=>openCampaign(b.dataset.edit)); $$('[data-del]',$('#contributionsRows')).forEach(b=>b.onclick=()=>removeCampaign(b.dataset.del));}
async function dashboard(){try{const d=await req(API+'/dashboard',{cacheTtl:1000}); const m=d.metrics||{}; $('#contributionStats').innerHTML=[['Tổng số hộ',m.total_households,'hộ','fa-house'],['Hộ phải đóng',m.due_households,'hộ','fa-hand-holding-dollar'],['Hộ được miễn',m.exempt_households,'hộ','fa-shield-heart'],['Đã nộp',m.paid_households,'hộ','fa-circle-check'],['Nộp một phần',m.partial_households,'hộ','fa-clock-rotate-left'],['Chưa nộp',m.unpaid_households,'hộ','fa-hourglass-half'],['Tổng nhân khẩu',m.total_population,'khẩu','fa-users'],['Khẩu phải thu',m.eligible_population,'khẩu','fa-user-check'],['Khẩu được miễn',m.exempt_population,'khẩu','fa-user-shield'],['Khẩu hoàn thành',m.completed_population,'khẩu','fa-check-double'],['Tổng phải thu',money(m.expected_total),'VNĐ','fa-file-invoice-dollar'],['Còn phải thu',money(m.debt_amount),'VNĐ','fa-sack-dollar']].map(card).join(''); renderCharts(d.charts||{});}catch(e){}}
function card(c){const value=typeof c[1]==='number'?num(c[1]):esc(c[1]); return '<article class="dashboard-kpi-card"><span><i class="fa-solid '+c[3]+'"></i></span><div><p>'+c[0]+'</p><strong>'+value+'</strong><em>'+c[2]+'</em></div></article>';}
function renderCharts(charts){$('#contributionCharts').innerHTML=[chartBox('Trạng thái hộ',charts.by_status),chartBox('Trạng thái nhân khẩu',charts.by_population_status),chartBox('Thu - miễn - còn phải thu',charts.financial,true)].join('');}
function chartBox(title,items,isMoney=false){items=items||[]; const max=Math.max(1,...items.map(i=>Number(i.value||0))); return '<div class="col-lg-4"><article class="content-card h-100"><h3 class="h6 mb-3">'+esc(title)+'</h3>'+items.map(i=>'<div class="mb-2"><div class="d-flex justify-content-between small"><span>'+esc(i.label)+'</span><strong>'+(isMoney?money(i.value):num(i.value))+'</strong></div><div class="progress" style="height:8px"><div class="progress-bar bg-success" style="width:'+Math.round(Number(i.value||0)*100/max)+'%"></div></div></div>').join('')+'</article></div>';}
async function openCampaign(id){ if(!can(id?'update':'create'))return toast('Tài khoản không có quyền thao tác','warning'); await catalogs(); const f=$('#contributionForm'); f.reset(); f.elements.id.value=''; f.elements.year.value=new Date().getFullYear(); f.elements.unit.value='VNĐ/hộ'; f.elements.unit_type.value='HOUSEHOLD'; f.elements.status.value='ACTIVE'; setChecks('target_conditions',['ALL_HOUSEHOLDS']); setChecks('exemption_conditions',[]); if(id){const r=await req(API+'/'+id); Object.entries(r).forEach(([k,v])=>{if(f.elements[k])f.elements[k].value=v??'';}); setConfigChecks('target_conditions',r.target_config_json,['ALL_HOUSEHOLDS']); setConfigChecks('exemption_conditions',r.exemption_config_json,[]); f.elements.id.value=r.id;} bootstrap.Modal.getOrCreateInstance($('#contributionModal')).show();}
function setConfigChecks(name,json,def){let cfg={}; try{cfg=typeof json==='string'?JSON.parse(json||'{}'):(json||{});}catch(e){} setChecks(name,cfg.conditions||def); const f=$('#contributionForm'); if(f.elements.age_from)f.elements.age_from.value=cfg.age_from||''; if(f.elements.age_to)f.elements.age_to.value=cfg.age_to||'';}
function setChecks(name,vals){$$('input[name="'+name+'"]').forEach(i=>{i.checked=(vals||[]).includes(i.value);});}
function selected(name){return $$('input[name="'+name+'"]:checked').map(i=>i.value);}
async function saveCampaign(e){e.preventDefault(); const f=e.currentTarget, body=Object.fromEntries(new FormData(f).entries()); body.target_conditions=selected('target_conditions'); body.exemption_conditions=selected('exemption_conditions'); try{await req(body.id?API+'/'+body.id:API,{method:body.id?'PUT':'POST',body}); bootstrap.Modal.getOrCreateInstance($('#contributionModal')).hide(); toast('Đã lưu khoản thu'); load();}catch(err){toast(err.message,'danger');}}
async function removeCampaign(id){if(!can('delete'))return toast('Tài khoản không có quyền xóa','warning'); if(!confirm('Xóa đợt thu này?'))return; try{await req(API+'/'+id,{method:'DELETE'}); toast('Đã xóa đợt thu'); load();}catch(e){toast(e.message,'danger');}}
async function loadTracking(){if(!state.campaign)return; const card=$('#contributionTrackingCard'),payment=$('#contributionPaymentFilter').value; card.classList.remove('d-none'); $('#contributionTrackingTitle').textContent='Theo dõi hộ - '+state.campaign.name; const p=new URLSearchParams({page:1,pageSize:100}); if(payment)p.set('payment_status',payment); const data=await req(API+'/'+state.campaign.id+'/households?'+p.toString()); $('#contributionTrackingTotal').textContent='Tổng số: '+num(data.total)+' hộ'; $('#contributionTrackingRows').innerHTML=(data.items||[]).map(trackRow).join('')||'<tr><td colspan="10" class="text-center text-muted py-4">Chưa có dữ liệu theo dõi</td></tr>'; $$('[data-pay]',$('#contributionTrackingRows')).forEach(b=>b.onclick=()=>openPayment(JSON.parse(b.dataset.pay))); syncLabels(card);}
function trackRow(r){return '<tr><td>'+esc(r.household_code)+'</td><td><strong>'+esc(r.head_citizen_name)+'</strong><div class="text-muted small">'+esc(r.address)+'</div></td><td><span class="badge text-bg-light">'+esc(r.payment_status_label)+'</span></td><td>'+num(r.chargeable_count)+'</td><td>'+num(r.exempt_count)+'</td><td>'+money(r.expected_amount)+'</td><td>'+money(r.paid_amount)+'</td><td>'+money(r.debt_amount)+'</td><td>'+esc(r.receipt_number)+'</td><td class="text-end"><button class="btn btn-sm btn-outline-primary" data-pay=\''+esc(JSON.stringify(r))+'\'><i class="fa-solid fa-pen"></i></button></td></tr>';}
async function openPayment(r){if(!can('update'))return toast('Tài khoản không có quyền thao tác','warning'); await catalogs(); const f=$('#contributionPaymentForm'); f.reset(); Object.entries(r).forEach(([k,v])=>{if(f.elements[k])f.elements[k].value=v??'';}); f.elements.campaign_id.value=state.campaign.id; f.elements.household_id.value=r.household_id; $('#contributionPaymentHousehold').textContent=r.household_code+' - '+r.head_citizen_name+' | Phải thu: '+money(r.expected_amount)+' | Còn nợ: '+money(r.debt_amount); bootstrap.Modal.getOrCreateInstance($('#contributionPaymentModal')).show();}
async function savePayment(e){e.preventDefault(); const f=e.currentTarget, body=Object.fromEntries(new FormData(f).entries()); try{await req(API+'/'+body.campaign_id+'/households/'+body.household_id,{method:'PUT',body}); bootstrap.Modal.getOrCreateInstance($('#contributionPaymentModal')).hide(); toast('Đã cập nhật thu tiền'); loadTracking(); dashboard();}catch(err){toast(err.message,'danger');}}
function exportReport(format){const p=params(); p.set('type',format==='preview'?'contributions-summary':'contributions'); if(state.campaign)p.set('campaign_id',state.campaign.id); const url=format==='pdf'?'/api/reports/export-pdf':format==='excel'?'/api/reports/export-excel':'/api/reports/preview'; window.open(url+'?'+p.toString(),'_blank','noopener');}
function syncLabels(root){if(typeof thon09SyncResponsiveTableLabels==='function')thon09SyncResponsiveTableLabels(root);}
function debounce(fn,ms){let t;return function(){clearTimeout(t);t=setTimeout(()=>fn.apply(this,arguments),ms);};}
})();
